kdrop-filter: blur(4px);\n          backdrop-filter: blur(4px);\n  animation: _ngcontent-%COMP%_fadeIn 0.15s ease-out;\n}\n\n.modal-content[_ngcontent-%COMP%] {\n  background: #ffffff;\n  padding: 28px;\n  border-radius: 12px;\n  width: 500px;\n  max-width: 90%;\n  box-shadow: 0 20px 25px -5px rgba(0,0,0,0.1);\n}\n\n.modal-header[_ngcontent-%COMP%] {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  border-bottom: 1px solid #f1f5f9;\n  padding-bottom: 14px;\n  margin-bottom: 18px;\n}\n\n.modal-header[_ngcontent-%COMP%]   h3[_ngcontent-%COMP%] {\n  margin: 0;\n  color: #0f172a;\n  font-size: 16px;\n  font-weight: 700;\n  display: flex;\n  align-items: center;\n  gap: 8px;\n}\n\n.modal-header[_ngcontent-%COMP%]   h3[_ngcontent-%COMP%]   i[_ngcontent-%COMP%] {\n  color: #0ea5e9;\n}\n\n.close-btn[_ngcontent-%COMP%] {\n  background: none;\n  border: none;\n  font-size: 26px;\n  color: #94a3b8;\n  cursor: pointer;\n  line-height: 1;\n}\n\n.close-btn[_ngcontent-%COMP%]:hover {\n  color: #475569;\n}\n\n.modal-body[_ngcontent-%COMP%] {\n  display: flex;\n  flex-direction: column;\n  gap: 12px;\n}\n\n.info-row[_ngcontent-%COMP%] {\n  display: flex;\n  font-size: 13.5px;\n}\n\n.info-label[_ngcontent-%COMP%] {\n  color: #64748b;\n  font-weight: 500;\n  width: 150px;\n  flex-shrink: 0;\n}\n\n.info-value[_ngcontent-%COMP%] {\n  color: #334155;\n}\n\n.info-value.text-slate[_ngcontent-%COMP%] {\n  color: #0f172a;\n  font-weight: 600;\n}\n\n.summary-box[_ngcontent-%COMP%] {\n  margin-top: 8px;\n  padding: 12px;\n  background: #f8fafc;\n  border-radius: 6px;\n  border-left: 4px solid #0ea5e9;\n}\n\n.summary-title[_ngcontent-%COMP%] {\n  color: #0f172a;\n  font-weight: 600;\n  font-size: 13px;\n  display: block;\n  margin-bottom: 6px;\n}\n\n.summary-text[_ngcontent-%COMP%] {\n  margin: 0;\n  color: #475569;\n  font-size: 13px;\n  line-height: 1.5;\n  white-space: pre-line;\n}\n\n.modal-footer[_ngcontent-%COMP%] {\n  margin-top: 22px;\n  border-top: 1px solid #f1f5f9;\n  padding-top: 14px;\n  display: flex;\n  justify-content: flex-end;\n}\n\n.btn-secondary[_ngcontent-%COMP%] {\n  background: #f1f5f9;\n  color: #475569;\n  border: 1px solid #e2e8f0;\n  padding: 8px 16px;\n  border-radius: 6px;\n  font-size: 13px;\n  font-weight: 600;\n  cursor: pointer;\n  transition: background 0.15s;\n}\n\n.btn-secondary[_ngcontent-%COMP%]:hover {\n  background: #e2e8f0;\n}\n\n@keyframes _ngcontent-%COMP%_fadeIn { \n  from { opacity: 0; transform: translateY(4px); } \n  to { opacity: 1; transform: translateY(0); } \n}\n\n/*# sourceMappingURL=data:application/json;charset=utf-8;base64, */"]
